def countParenth(symb, oper, n):
    F = [[0 for i in range(n + 1)] for i in range(n + 1)]
    T = [[0 for i in range(n + 1)] for i in range(n + 1)]
    for i in range(n):
        if symb[i] == 'F':
            F[i][i] = 1
        else:
            F[i][i] = 0
        if symb[i] == 'T':
            T[i][i] = 1
        else:
            T[i][i] = 0
    for gap in range(1, n):
        i = 0
        for j in range(gap, n):
            T[i][j] = F[i][j] = 0
            for g in range(gap):
                k = i + g
                tik = T[i][k] + F[i][k]
                tkj = T[k + 1][j] + F[k + 1][j]
                if oper[k] == '&':
                    T[i][j] += T[i][k] * T[k + 1][j]
                    F[i][j] += tik * tkj - T[i][k] * T[k + 1][j]
                if oper[k] == '|':
                    F[i][j] += F[i][k] * F[k + 1][j]
