    n = len(s1)
    m = len(s2)
    lcs = [[0 for x in range(m + 1)] for y in range(n + 1)]
    cnt = [[0 for x in range(m + 1)] for y in range(n + 1)]
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            lcs[i][j] = max(lcs[i - 1][j], lcs[i][j - 1])
            if s1[i - 1] == s2[j - 1]:
